#include<bits/stdc++.h>
using namespace std;
int n,m,k;
int fa[400010],siz[400010];
struct Stack
{
    int x,y;
}s[3200010];
int top;
struct edge
{
    int x,y;
};
vector<edge> t[1600010];
int find(int x)
{
    while(x!=fa[x])
    {
        x=fa[x];
    }
    return x;
}
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(siz[a]>siz[b])
    {
        swap(a,b);
    }
    s[++top]=(Stack){a,b};
    siz[b]+=siz[a];
    fa[a]=b;
}
void update(int x,int l,int r,int L,int R,edge v)
{
    if(L>R||l>R||L>r)
    {
        return;
    }
    if(L<=l&&r<=R)
    {
        t[x].push_back(v);
        return;
    }
    int mid=(l+r)>>1;
    update(x<<1,l,mid,L,R,v);
    update(x<<1|1,mid+1,r,L,R,v);
}
void solve(int x,int l,int r)
{
    int flag=1;
    int lst=top;
    for(auto i:t[x])
    {
        int a=find(i.x),b=find(i.y);
        if(a==b)
        {
            for(int i=l;i<=r;i++)
            {
                printf("No\n");
            }
            flag=0;
            break;
        }
        merge(i.x,i.y+n);
        merge(i.x+n,i.y);
    }
    if(flag)
    {
        if(l==r)
        {
            printf("Yes\n");
        }
        else
        {
            int mid=(l+r)>>1;
            solve(x<<1,l,mid);
            solve(x<<1|1,mid+1,r);
        }
    }
    while(top>lst)
    {
        int k=s[top].x;
        while(k!=fa[k])
        {
            k=fa[k];
            siz[k]-=siz[s[top].x];
        }
        fa[s[top].x]=s[top].x;
        top--;
    }
}
int main()
{
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++)
    {
        int x,y,l,r;
        scanf("%d%d%d%d",&x,&y,&l,&r);
        update(1,1,k,l+1,r,(edge){x,y});
    }
    for(int i=1;i<=n*2;i++)
    {
        fa[i]=i;
        siz[i]=1;
    }
    solve(1,1,k);
    return 0;
}
